85	void
86	ngx_slab_sizes_init(void)
87	{
88	    ngx_uint_t  n;
89	
90	    ngx_slab_max_size = ngx_pagesize / 2;
91	    ngx_slab_exact_size = ngx_pagesize / (8 * sizeof(uintptr_t));
92	    for (n = ngx_slab_exact_size; n >>= 1; ngx_slab_exact_shift++) {
93	        /* void */
